var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>내가 준 정보는 도움이 되었나 모르겠군. 몽타뉴.</color>","JPN":"<color=#ffd34c>私が教えた情報は役に立ったかね？　モンターニュ。</color>","ENG":"<color=#ffd34c>I’m not sure if the information I gave was of any help, Montagne.</color>","TWN":"<color=#ffd34c>蒙塔妮，我提供的情報有幫上忙嗎？</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"아주 큰 도움이 됐어, 시솝.","JPN":"おおいに役立った、シソップ。","ENG":"It was of great help, Sysop.","TWN":"非常有幫助，錫索普。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"네가 아니었다면 마에스트로의 소재를 찾지도 못했겠지. 고맙다.","JPN":"あなたじゃなかったらマエストロの居場所を見つけることもできなかったよ。ありがとう。","ENG":"If it weren’t for you, I would not have found Maestra’s location. Thank you.","TWN":"多虧你我才能找到指揮家的下落，謝謝。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>하하, 감격스럽군. 솔직한 감사 인사는 오랜만이야.</color>","JPN":"<color=#ffd34c>はは、感激だね。素直な感謝の言葉は久しぶりだ。</color>","ENG":"<color=#ffd34c>Ha ha, I’m flattered. It’s been awhile since someone thanked me so honestly.</color>","TWN":"<color=#ffd34c>哈哈，真令人感動，好久沒人這麼直接地表達謝意。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>버려진 형제들이라…… 확실히 구 관리국을 증오하는 자들에게 어울리는 이름이야.</color>","JPN":"<color=#ffd34c>捨てられた兄弟か……確かに旧管理局を憎む者たちにはふさわしい名前だ。</color>","ENG":"<color=#ffd34c>The Brothers Abandoned... A fitting name for those who despise the Old Administration.</color>","TWN":"<color=#ffd34c>被遺棄的兄弟們……這個名字確實很適合痛恨舊管理局的人。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>마지막까지 건투를 기원하지.</color>","JPN":"<color=#ffd34c>最後まで健闘することを祈るよ。</color>","ENG":"<color=#ffd34c>I wish you all the best until the end.</color>","TWN":"<color=#ffd34c>希望你們可以奮戰到最後一刻。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"몽타뉴 님, 셰나가 메이즈 전대와 교전을 개시했습니다.","JPN":"モンターニュ様、シェナがメイズ戦隊と交戦を開始しました。","ENG":"Montagne, Shena has opened fire on Maze Division.","TWN":"蒙塔妮，世娜已經和梅茲戰隊開戰。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"예상했던 시간보다 오래 못 버텼군. 정부군이 움직였나?","JPN":"想定していた時間より長く持たなかったね。政府軍が動いた？","ENG":"That didn’t take as long as I thought it would. Have the government forces made a move?","TWN":"比我預期的還快呢，那政府軍有動作嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"아뇨. 정부군은 움직이지 않았어요.","JPN":"いいえ、政府軍は動いていません。","ENG":"No. The government forces haven’t made a move.","TWN":"沒有，政府軍沒有動作。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"그보다 보안국의 동향이 수상해요. 동지들이 염탐꾼들을 색출해냈습니다.","JPN":"それより保安局の動きが怪しいです。同志たちがスパイを探し出しました。","ENG":"What’s more, the Department of National Security has been acting suspiciously. Comrades have rooted out some of their spies.","TWN":"倒是安全局有點可疑，我們已經派人去查看。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……마에스트로가 거래를 했나 보군.","JPN":"……マエストロが取引をしたようね。","ENG":"...Maestra must have made a deal with them.","TWN":"……看來指揮家有進行交易。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"몽타뉴 님?","JPN":"モンターニュ様？","ENG":"Montagne?","TWN":"蒙塔妮？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"계획은 실패할 수 없고, 우리는 죽을 거야.","JPN":"計画に失敗はないし、私たちは死ぬだろう。","ENG":"The plan cannot fail, and we most certainly will die.","TWN":"計畫絕對不許失敗，失敗的話就是死路一條！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"구원 기사단이 허신을 불러들이려 하는 지금, 관리자는 이런 <color=#ffd34c>사소한</color> 일에 신경 쓰지 못할 테니까.","JPN":"救世騎士団が虚神を呼び寄せようとする今、管理者はこんな<color=#ffd34c>些細</color>なことに気を配る余裕がないから。","ENG":"Now that the Knights of Redemption are trying to summon the Hollow God, The Administrator won’t be able to care about a <color=#ffd34c>trivial</color> matter such as this.","TWN":"趁現在救贖騎士團在召喚幻神，管理者應該沒心力管這種<color=#ffd34c>雞毛蒜皮的事</color>。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"참 웃기지?","JPN":"笑えるよね？","ENG":"Isn’t it funny?","TWN":"很可笑吧？"},"stage":{"bg":"HARMONY_05","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"구원 기사단이나, 엘리시움 필하모닉이나 세계를 멸망시킬 수 있어.","JPN":"救世騎士団も、エリシウムフィルハーモニーも世界を滅ぼすことができる。","ENG":"Both the Knights of Redemption and the Elysium Philharmonic have the power to destroy the world.","TWN":"無論是救贖騎士團或是愛樂組織，他們都能夠毀滅世界。"},"stage":{"bg":"HARMONY_05","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"하지만 어느 쪽을 먼저 대응해야 하냐고 묻는다면……. 지금은 나도 전자를 택할 거야.","JPN":"しかしどっちを優先すべきかと言われると……今は私も前者を選ぶだろうね。","ENG":"But if you were to ask me which to take care of first... I’d choose the former as well.","TWN":"但你若問我，現在要先對付哪一邊……現在的我也會選擇前者。"},"stage":{"bg":"HARMONY_05","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"설령 살아남는다고 해도 조직은 나를 가만두지 않겠지.","JPN":"たとえ生き延びるとしても、組織は私を放っておかない。","ENG":"Even if I somehow manage to survive, the organization will not let me go.","TWN":"就算我活下來，組織也不會放過我的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"관리국에 대한 복수는 내팽개치고 조직의 전력을 멋대로 끌어다 썼으니까.","JPN":"管理局に対する復讐はほっぽらかして組織の戦力を勝手に借りていったからね。","ENG":"I’ve abandoned the revenge on the Administration and used their power as I’ve pleased.","TWN":"誰叫我把報復管理局的事拋諸腦後，還擅自動用組織的戰力。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"……괜찮습니다, 몽타뉴님. 저희는 여기서 죽을 테니까요.","JPN":"……大丈夫です、モンターニュ様。私たちはここで死にますから。","ENG":"...It’s okay, Montagne. We’re all going to die here anyways.","TWN":"……無所謂，蒙塔妮。反正我們一定會死在這裡。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"결국 빠르고 깨끗하게 죽느냐, 느리고 고통스럽게 죽느냐의 차이죠.","JPN":"結局は早く潔く死ぬか、遅く苦しく死ぬかの差しかありません。","ENG":"It’s just a matter of whether our deaths will be quick and painless, or slowly and painfully.","TWN":"差別只在於怎麼個死法，是死得痛快，還是死得痛苦？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그래……. 그래야지.","JPN":"そう……そうしないとね。","ENG":"Yeah... That’s right.","TWN":"沒錯……就是這樣。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"예전에 마에스트로와 싸울 때는 우리가 지켜야 할 게 너무 많았어.","JPN":"この前、マエストロと戦ったときは守るべきものが多すぎた。","ENG":"When we fought Maestra before, there were so many things we were fighting to protect.","TWN":"上次和指揮家一戰，我們要保護的東西太多。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"하지만 이번에는 정반대야.","JPN":"でも、今は正反対よ。","ENG":"But this time it’s the complete opposite.","TWN":"但這次可不一樣！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"몽타뉴 님, 퍼레이드가 막바지에 접어들었습니다.","JPN":"モンターニュ様、パレードが大詰めに入りました。","ENG":"Montagne, the parade is coming to an end.","TWN":"蒙塔妮，遊行已經進入尾聲，"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"곧 오케스트라 공연이 시작될 겁니다.","JPN":"もうすぐオーケストラ公演が始まります。","ENG":"The orchestra will begin soon.","TWN":"接下來就是管弦樂團的表演。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"좋아. 기폭 준비하고 각자 위치로 이동한다.","JPN":"わかった。起爆の準備をし、各々の位置へ移動する。","ENG":"Okay. Everyone prepare for detonation and move to your assigned positions.","TWN":"好，準備引爆，大家各就各位！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};